import{_ as a,o as r,c as e,ag as o}from"./chunks/framework.BmJvwvJl.js";const g=JSON.parse('{"title":"当程序员开始做内容","description":"","frontmatter":{"layout":"home","hero":{"name":"XHSOps","text":"小红书内容运营的正确打开方式","tagline":"在 Claude Code 里打 /xhs:quick，一篇笔记就写好了。经验还能沉淀下来。","actions":[{"theme":"brand","text":"2 分钟快速开始","link":"/guide/getting-started"},{"theme":"alt","text":"先看核心概念","link":"/concepts/why-xhsops"}]}},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),d={name:"index.md"};function i(l,t,p,s,n,h){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="当程序员开始做内容" tabindex="-1">当程序员开始做内容 <a class="header-anchor" href="#当程序员开始做内容" aria-label="Permalink to &quot;当程序员开始做内容&quot;">​</a></h1><p>你可能是这种感觉——</p><p>写代码的时候，你很自信。一个需求来了，你会先想架构、拆任务、定接口，然后一行一行把代码码出来。你知道怎么把一个大问题拆成小问题，也知道怎么让代码可维护、可扩展。</p><p>但是让你写一篇小红书笔记？</p><p>完了，完全是另外一套思路。</p><p>你打开编辑器，憋了半小时，写了两行字。你不知道读者爱看什么，不知道标题怎么起，甚至不知道一篇笔记应该多长。你去刷别人的爆款，看完还是一头雾水——「他们怎么做到的？」</p><p><strong>写代码和做内容，用的是两套完全不同的思维方式。</strong></p><hr><h1 id="一人公司的困境" tabindex="-1">一人公司的困境 <a class="header-anchor" href="#一人公司的困境" aria-label="Permalink to &quot;一人公司的困境&quot;">​</a></h1><p>现在很多人都在说「一人公司」——一个人就是一个公司，既要写代码，又要写内容，又要搞运营。</p><p>听起来很酷，但实际上：</p><ul><li>你花 3 小时写代码，产生 3 小时的价值</li><li>你花 3 小时写内容，产生 3 小时的价值</li></ul><p><strong>但问题是：你写的内容，下个月还能用吗？</strong></p><p>大多数人的答案是：不能。</p><p>因为：</p><ul><li>你的选题是随机想的</li><li>你的写作风格是随机的</li><li>你的经验是散落的</li><li>你的复盘是空白的</li></ul><p>你不是在运营一个「系统」，你只是在「随机生产内容」。</p><hr><h1 id="所以这个项目是干什么的" tabindex="-1">所以这个项目是干什么的 <a class="header-anchor" href="#所以这个项目是干什么的" aria-label="Permalink to &quot;所以这个项目是干什么的&quot;">​</a></h1><p>XHSOps 是为所有程序员同行做的。</p><p>我是一个写了十多年代码的程序员，最近两年才开始认真做小红书。跟大多数人一样，一开始我觉得内容嘛，不就是「写」吗？</p><p>结果发现完全不是那么回事。</p><p><strong>内容创作是一个系统性工程：</strong></p><ul><li>你需要知道你的读者是谁</li><li>你需要确定你的内容定位</li><li>你需要规划选题方向</li><li>你需要判断热点值不值得跟</li><li>你需要审核自己的内容</li><li>你需要沉淀复盘经验</li></ul><p>这些问题，写代码的时候你根本没遇到过。</p><p><strong>于是我做了一件事：把内容运营，变成我可以理解的「工程问题」。</strong></p><hr><h1 id="xhsops-怎么解决这个问题" tabindex="-1">XHSOps 怎么解决这个问题 <a class="header-anchor" href="#xhsops-怎么解决这个问题" aria-label="Permalink to &quot;XHSOps 怎么解决这个问题&quot;">​</a></h1><p>它不是又一个 AI 写作工具。这个世界上不缺能帮你写东西的 AI。</p><p><strong>XHSOps 是你在 AI 工具里的「内容运营操作系统」。</strong></p><p>它帮你把每一次创作拆成清晰的步骤：</p><ol><li><strong>选题</strong> - 不是随机想，而是有策略地规划</li><li><strong>Brief</strong> - 每次创作都有计划</li><li><strong>起草</strong> - AI 帮你写，但你掌控方向</li><li><strong>审核</strong> - 有标准可循，不是凭感觉</li><li><strong>发布</strong> - 生成可以直接用的发布包</li><li><strong>复盘</strong> - 经验沉淀下来，下次还能用</li></ol><p><strong>更重要的是：它会让 AI 记住你学过的东西。</strong></p><p>下次你再让它写，它会参考你上次成功的写法、避开你踩过的坑、借鉴你沉淀下来的经验。</p><hr><h1 id="程序员怎么用" tabindex="-1">程序员怎么用 <a class="header-anchor" href="#程序员怎么用" aria-label="Permalink to &quot;程序员怎么用&quot;">​</a></h1><p>你不用学什么新东西。</p><p>你只需要在你已经用的 AI 工具里，直接说话就行：</p><table tabindex="0"><thead><tr><th>命令</th><th>作用</th></tr></thead><tbody><tr><td><code>/xhs:quick</code></td><td>选题卡壳？一句话就能开始写</td></tr><tr><td><code>/xhs:hot</code></td><td>看到一个热点，先让 AI 帮你判断值不值得追</td></tr><tr><td><code>/xhs:plan</code></td><td>想做系列内容？AI 帮你拆解成每周任务</td></tr><tr><td><code>/xhs:review</code></td><td>写完了？AI 帮你审一遍</td></tr><tr><td><code>/xhs:publish</code></td><td>一键生成带话题、标签的发布包</td></tr><tr><td><code>/xhs:archive</code></td><td>归档这次创作的复盘，经验沉淀下来</td></tr></tbody></table><p><strong>你说话，AI 干活。</strong><strong>经验自动沉淀，下次继续用。</strong></p><hr><h1 id="什么时候该用" tabindex="-1">什么时候该用 <a class="header-anchor" href="#什么时候该用" aria-label="Permalink to &quot;什么时候该用&quot;">​</a></h1><table tabindex="0"><thead><tr><th>场景</th><th>推荐工作流</th></tr></thead><tbody><tr><td>突然有个想法想记录下来</td><td>Quick</td></tr><tr><td>看到一个热点想跟进</td><td>Trend</td></tr><tr><td>想做一个系列的内容</td><td>Campaign</td></tr><tr><td>想规划一个月的更新</td><td>Campaign</td></tr></tbody></table><hr><h1 id="真正重要的是什么" tabindex="-1">真正重要的是什么 <a class="header-anchor" href="#真正重要的是什么" aria-label="Permalink to &quot;真正重要的是什么&quot;">​</a></h1><p>XHSOps 解决的不是「怎么写」的问题。</p><p><strong>XHSOps 解决的是「写了之后留下了什么」的问题。</strong></p><p>当你用这个工具的时候，你不是在进行一次性的对话。 你是在搭建一个会成长的内容系统。</p><p>你的每一次创作，都在为未来积累。</p><hr><h3 id="现在开始" tabindex="-1">现在开始 <a class="header-anchor" href="#现在开始" aria-label="Permalink to &quot;现在开始&quot;">​</a></h3><p>花 2 分钟<a href="/XHSOps/guide/getting-started">初始化你的内容运营工作流</a>，然后永远告别从零开始。</p><p>或者，先看看<a href="/XHSOps/concepts/why-xhsops">核心概念</a>——看看我是怎么把内容运营变成「工程问题」的。</p>',53)])])}const u=a(d,[["render",i]]);export{g as __pageData,u as default};
